SELECT item_name
FROM balance_sheet_items
WHERE item_id = 0;

SELECT item_name
FROM balance_sheet_items
WHERE category = 'balance sheet';

SELECT DISTINCT company_name 
FROM companies 
WHERE country = 'USA';

SELECT data_id, company_id, item_id
FROM financial_data
WHERE company_id = 0 AND item_id = 0 AND value > 100000;

SELECT item_type, category, COUNT(item_id) AS item_count
FROM balance_sheet_items
GROUP BY item_type, category;
